  1→import React, { useCallback, useEffect, useRef, useState } from 'react';
  2→import { addons } from 'storybook/internal/manager-api';
  3→import { useStorybookState } from 'storybook/internal/manager-api';
  4→import { EVENTS } from './constants';
  5→import { useIndexedDB } from './useIndexedDB';
  6→import { CodeMirrorEditor, type CodeMirrorEditorHandle } from './CodeMirrorEditor';
  7→
  8→function idbKeyFor(storyId: string) {
  9→  return `sdui-json-${storyId}`;
 10→}
 11→
 12→function getChannel() {
 13→  try { return addons.getChannel(); } catch { return null; }
 14→}
 15→
 16→export function JsonEditorPanel() {
 17→  const state = useStorybookState();
 18→  const storyId = state.storyId ?? '';
 19→
 20→  const [defaultJson, setDefaultJson] = useState<string>('');
 21→  const [text, setText] = useState<string>('');
 22→  const [error, setError] = useState<string | null>(null);
 23→  const [dirty, setDirty] = useState(false);
 24→  const debounceRef = useRef<ReturnType<typeof setTimeout> | null>(null);
 25→  const editorRef = useRef<CodeMirrorEditorHandle>(null);
 26→
 27→  const { stored, save, remove, ready } = useIndexedDB(idbKeyFor(storyId));
 28→
 29→  useEffect(() => {
 30→    return () => {
 31→      if (debounceRef.current) clearTimeout(debounceRef.current);
 32→    };
 33→  }, []);
 34→
 35→  useEffect(() => {
 36→    const channel = getChannel();
 37→    if (!channel) return;
