import React, { useCallback, useEffect, useRef, useState } from 'react';
import { addons } from 'storybook/internal/manager-api';
import { useStorybookState } from 'storybook/internal/manager-api';
import { EVENTS } from './constants';
import { useIndexedDB } from './useIndexedDB';
import { CodeMirrorEditor, type CodeMirrorEditorHandle } from './CodeMirrorEditor';

function idbKeyFor(storyId: string) {
  return `sdui-json-${storyId}`;
}

function getChannel() {
  try { return addons.getChannel(); } catch { return null; }
}

export function JsonEditorPanel() {
  const state = useStorybookState();
  const storyId = state.storyId ?? '';

  const [defaultJson, setDefaultJson] = useState<string>('');
  const [text, setText] = useState<string>('');
  const [error, setError] = useState<string | null>(null);
  const [dirty, setDirty] = useState(false);
  const debounceRef = useRef<ReturnType<typeof setTimeout> | null>(null);
  const editorRef = useRef<CodeMirrorEditorHandle>(null);

  const { stored, save, remove, ready } = useIndexedDB(idbKeyFor(storyId));

  useEffect(() => {
    return () => {
      if (debounceRef.current) clearTimeout(debounceRef.current);
    };
  }, []);

  useEffect(() => {
    const channel = getChannel();
    if (!channel) return;

    const onSetDefault = (json: string) => setDefaultJson(json);
    channel.on(EVENTS.SET_DEFAULT_JSON, onSetDefault);
    channel.emit(EVENTS.REQUEST_DEFAULT);

    return () => { channel.off(EVENTS.SET_DEFAULT_JSON, onSetDefault); };
  }, [storyId]);

  useEffect(() => {
    if (!ready || !defaultJson) return;
    const initial = stored ?? defaultJson;
    setText(initial);
    setDirty(!!stored);
    setError(null);
  }, [ready, stored, defaultJson, storyId]);

  const handleChange = useCallback(
    (value: string) => {
      setText(value);

      if (debounceRef.current) clearTimeout(debounceRef.current);

      debounceRef.current = setTimeout(() => {
        try {
          const parsed = JSON.parse(value);
          save(value);
          setDirty(true);
          getChannel()?.emit(EVENTS.UPDATE_JSON, parsed);
        } catch {
          save(value);
          setDirty(true);
        }
      }, 400);
    },
    [save],
  );

  const handleValidationChange = useCallback(
    (hasErrors: boolean, message: string | null) => {
      setError(hasErrors ? message : null);
    },
    [],
  );

  const handleReset = useCallback(() => {
    remove();
    setText(defaultJson);
    editorRef.current?.setValue(defaultJson);
    setDirty(false);
    setError(null);
    try {
      getChannel()?.emit(EVENTS.UPDATE_JSON, JSON.parse(defaultJson));
    } catch { /* noop */ }
  }, [defaultJson, remove]);

  const handleFormat = useCallback(() => {
    const currentText = editorRef.current?.getValue() ?? '';
    try {
      const parsed = JSON.parse(currentText);
      const formatted = JSON.stringify(parsed, null, 2);
      setText(formatted);
      editorRef.current?.setValue(formatted);
      save(formatted);
      getChannel()?.emit(EVENTS.UPDATE_JSON, parsed);
      setError(null);
    } catch (e) {
      setError((e as Error).message);
    }
  }, [save]);

  if (!storyId) {
    return <div style={styles.empty}>Select a story to edit its JSON.</div>;
  }

  return (
    <div style={styles.container}>
      <div style={styles.toolbar}>
        <span style={styles.label}>
          SDUI JSON {dirty && <span style={styles.badge}>edited</span>}
        </span>
        <div style={styles.actions}>
          <button style={styles.btn} onClick={handleFormat}>
            Format
          </button>
          <button
            style={{ ...styles.btn, ...styles.btnReset }}
            onClick={handleReset}
            disabled={!dirty}
          >
            Reset
          </button>
        </div>
      </div>

      {error && <div style={styles.error}>JSON Error: {error}</div>}

      <div style={styles.editorContainer}>
        <CodeMirrorEditor
          ref={editorRef}
          value={text}
          onChange={handleChange}
          onValidationChange={handleValidationChange}
        />
      </div>
    </div>
  );
}

const styles: Record<string, React.CSSProperties> = {
  container: {
    display: 'flex',
    flexDirection: 'column',
    height: '100%',
    fontFamily: 'monospace',
    fontSize: 12,
  },
  toolbar: {
    display: 'flex',
    justifyContent: 'space-between',
    alignItems: 'center',
    padding: '6px 10px',
    borderBottom: '1px solid #e0e0e0',
    background: '#fafafa',
  },
  label: {
    fontWeight: 600,
    fontSize: 13,
    color: '#333',
  },
  badge: {
    display: 'inline-block',
    marginLeft: 6,
    padding: '1px 6px',
    borderRadius: 4,
    background: '#ff9800',
    color: '#fff',
    fontSize: 10,
    fontWeight: 700,
  },
  actions: {
    display: 'flex',
    gap: 6,
  },
  btn: {
    padding: '4px 10px',
    borderRadius: 4,
    border: '1px solid #ccc',
    background: '#fff',
    cursor: 'pointer',
    fontSize: 12,
  },
  btnReset: {
    borderColor: '#ff5722',
    color: '#ff5722',
  },
  error: {
    padding: '6px 10px',
    background: '#ffebee',
    color: '#c62828',
    fontSize: 12,
    borderBottom: '1px solid #ef9a9a',
  },
  editorContainer: {
    flex: 1,
    overflow: 'hidden',
  },
  empty: {
    padding: 20,
    color: '#999',
    textAlign: 'center' as const,
  },
};

