import type { JSONSchemaType } from 'ajv';
import { SDUI_KNOWN_TYPES } from '../../../src/services/sdui/models';

const knownTypes = [...SDUI_KNOWN_TYPES];

const spacingEnum = [
  'none', 'xxxs', 'xxs', 'xs', 'smaller', 'sm', 'md', 'lg', 'xl', 'xxl', 'xxxl',
];

const spacingProp = {
  type: 'string' as const,
  nullable: true as const,
};

const conditionalSchema = {
  type: 'object' as const,
  properties: {
    rule: { type: 'object' as const },
  },
  required: ['rule'] as const,
  additionalProperties: false,
};

const componentPropsSchemas: Record<string, object> = {
  heading: {
    type: 'object',
    properties: {
      text: { type: 'string' },
      color: { type: 'string' },
      mt: spacingProp,
      mb: spacingProp,
      align: { type: 'string' },
      testID: { type: 'string' },
    },
    required: ['text'],
  },
  text: {
    type: 'object',
    properties: {
      text: { type: 'string' },
      type: { type: 'string' },
      color: { type: 'string' },
      colorBold: { type: 'string' },
      mt: spacingProp,
      mb: spacingProp,
      mr: spacingProp,
      ml: spacingProp,
      align: { type: 'string' },
      underline: { type: 'boolean' },
      testID: { type: 'string' },
    },
    required: ['text'],
  },
  section_heading: {
    type: 'object',
    properties: {
      text: { type: 'string' },
      color: { type: 'string' },
      mt: spacingProp,
      mb: spacingProp,
      align: { type: 'string' },
    },
    required: ['text'],
  },
  balance_display: {
    type: 'object',
    properties: {
      label: { type: 'string' },
      pointsFormatted: { type: 'string' },
      priceFormatted: { type: 'string' },
      mt: spacingProp,
      mb: spacingProp,
    },
    required: ['label', 'pointsFormatted', 'priceFormatted'],
  },
  points_input: {
    type: 'object',
    properties: {
      label: { type: 'string' },
      placeholder: { type: 'string' },
      keyboardType: { type: 'string' },
      textRight: { type: 'string' },
      textError: { type: 'string' },
      mb: spacingProp,
      contextKey: { type: 'string' },
    },
    required: ['label'],
  },
  button: {
    type: 'object',
    properties: {
      text: { type: 'string' },
      disabled: { type: 'boolean' },
      mt: spacingProp,
      mb: spacingProp,
      icon: { type: 'string' },
      isLoading: { type: 'boolean' },
      testID: { type: 'string' },
    },
    required: ['text'],
  },
  link: {
    type: 'object',
    properties: {
      text: { type: 'string' },
      color: { type: 'string' },
      mt: spacingProp,
      mb: spacingProp,
      align: { type: 'string' },
    },
    required: ['text'],
  },
  alert: {
    type: 'object',
    properties: {
      label: { type: 'string' },
      type: { type: 'string' },
      icon: { type: 'string' },
      mb: spacingProp,
    },
    required: ['label'],
  },
  list_text_icon: {
    type: 'object',
    properties: {
      items: {
        type: 'array',
        items: {
          type: 'object',
          properties: {
            icon: { type: 'string' },
            iconColor: { type: 'string' },
            iconColorShape: { type: 'string' },
            description: { type: 'string' },
            hasBackgroundIcon: { type: 'boolean' },
          },
          required: ['icon', 'description'],
        },
      },
      type: { type: 'string' },
      ml: spacingProp,
      mr: spacingProp,
      mb: spacingProp,
    },
    required: ['items'],
  },
  separator: {
    type: 'object',
    properties: {
      bgColor: { type: 'string' },
      height: { type: 'number' },
      width: { type: 'string' },
      mt: spacingProp,
      mb: spacingProp,
    },
  },
  icon_text_row: {
    type: 'object',
    properties: {
      icon: { type: 'string' },
      iconColor: { type: 'string' },
      iconSize: { type: 'string' },
      text: { type: 'string' },
      textType: { type: 'string' },
      textColor: { type: 'string' },
      mb: spacingProp,
    },
    required: ['icon', 'text'],
  },
  nav_header: {
    type: 'object',
    properties: {
      title: { type: 'string' },
    },
  },
  rich_text: {
    type: 'object',
    properties: {
      children: {
        type: 'array',
        items: {
          type: 'object',
          oneOf: [
            {
              properties: {
                type: { type: 'string', const: 'text' },
                value: { type: 'string' },
                bold: { type: 'boolean' },
                italic: { type: 'boolean' },
                color: { type: 'string' },
              },
              required: ['type', 'value'],
            },
            {
              properties: {
                type: { type: 'string', const: 'link' },
                text: { type: 'string' },
                to: { type: 'string' },
                trackEvent: { type: 'string' },
              },
              required: ['type', 'text', 'to'],
            },
            {
              properties: {
                type: { type: 'string', const: 'icon' },
                name: { type: 'string' },
                color: { type: 'string' },
                size: { type: 'number' },
              },
              required: ['type', 'name'],
            },
            {
              properties: {
                type: { type: 'string', const: 'br' },
              },
              required: ['type'],
            },
          ],
        },
      },
    },
    required: ['children'],
  },
};

const componentSchemaOneOf = knownTypes.map(type => ({
  if: { properties: { type: { const: type } } },
  then: {
    properties: {
      type: { const: type },
      props: componentPropsSchemas[type] || { type: 'object' as const },
      visible: conditionalSchema,
    },
    required: ['type', 'props'],
  },
}));

export const sduiScreenSchema = {
  $schema: 'http://json-schema.org/draft-07/schema#',
  type: 'object',
  properties: {
    id: { type: 'string' },
    context: { type: 'object' },
    header: {
      type: 'object',
      properties: {
        type: { type: 'string', enum: knownTypes },
        props: { type: 'object' },
        visible: conditionalSchema,
      },
      required: ['type', 'props'],
    },
    body: {
      type: 'array',
      items: {
        type: 'object',
        properties: {
          type: { type: 'string' },
          props: { type: 'object' },
          visible: conditionalSchema,
        },
        required: ['type', 'props'],
        allOf: componentSchemaOneOf,
      },
    },
    footer: {
      type: 'object',
      properties: {
        type: { type: 'string', enum: knownTypes },
        props: { type: 'object' },
        visible: conditionalSchema,
      },
      required: ['type', 'props'],
    },
  },
  required: ['id', 'body'],
};

export { knownTypes, componentPropsSchemas };

