import React, {
  forwardRef,
  useEffect,
  useImperativeHandle,
  useRef,
} from 'react';
import { EditorState } from '@codemirror/state';
import { EditorView, keymap, lineNumbers, highlightActiveLine, highlightActiveLineGutter, drawSelection, rectangularSelection } from '@codemirror/view';
import { json, jsonParseLinter } from '@codemirror/lang-json';
import { defaultKeymap, history, historyKeymap, indentWithTab } from '@codemirror/commands';
import { syntaxHighlighting, defaultHighlightStyle, bracketMatching, foldGutter, foldKeymap } from '@codemirror/language';
import { linter, lintGutter } from '@codemirror/lint';
import { searchKeymap, highlightSelectionMatches } from '@codemirror/search';

export interface CodeMirrorEditorHandle {
  getValue: () => string;
  setValue: (value: string) => void;
  getView: () => EditorView | null;
}

interface CodeMirrorEditorProps {
  value: string;
  onChange: (value: string) => void;
  onValidationChange?: (hasErrors: boolean, message: string | null) => void;
}

const sduiTheme = EditorView.theme({
  '&': {
    height: '100%',
    fontSize: '12px',
  },
  '.cm-scroller': {
    fontFamily: "'Ubuntu Mono', 'Menlo', 'Monaco', 'Consolas', monospace",
    lineHeight: '1.5',
    overflow: 'auto',
  },
  '.cm-content': {
    caretColor: '#528bff',
    padding: '4px 0',
  },
  '.cm-gutters': {
    background: '#f5f5f5',
    borderRight: '1px solid #e0e0e0',
    color: '#999',
    minWidth: '32px',
  },
  '.cm-activeLineGutter': {
    background: '#e8f0fe',
  },
  '.cm-activeLine': {
    background: '#f0f4ff',
  },
  '.cm-selectionBackground': {
    background: '#d7e4f9 !important',
  },
  '.cm-cursor': {
    borderLeftColor: '#528bff',
  },
  '.cm-matchingBracket': {
    background: '#c8e6c9',
    outline: '1px solid #81c784',
  },
  '.cm-foldGutter .cm-gutterElement': {
    cursor: 'pointer',
    padding: '0 4px',
  },
  '.cm-lint-marker': {
    width: '10px',
    height: '10px',
  },
  '.cm-lintRange-error': {
    backgroundImage: 'none',
    textDecoration: 'underline wavy #e53935',
    textUnderlineOffset: '3px',
  },
  '.cm-lintRange-warning': {
    backgroundImage: 'none',
    textDecoration: 'underline wavy #fb8c00',
    textUnderlineOffset: '3px',
  },
  '.cm-diagnostic': {
    padding: '4px 8px',
    fontSize: '12px',
  },
  '.cm-diagnostic-error': {
    borderLeft: '3px solid #e53935',
  },
  '.cm-tooltip': {
    border: '1px solid #e0e0e0',
    borderRadius: '4px',
    boxShadow: '0 2px 8px rgba(0,0,0,0.12)',
  },
});

export const CodeMirrorEditor = forwardRef<
  CodeMirrorEditorHandle,
  CodeMirrorEditorProps
>(function CodeMirrorEditor({ value, onChange, onValidationChange }, ref) {
  const containerRef = useRef<HTMLDivElement>(null);
  const viewRef = useRef<EditorView | null>(null);
  const onChangeRef = useRef(onChange);
  const onValidationChangeRef = useRef(onValidationChange);
  const isExternalUpdate = useRef(false);

  onChangeRef.current = onChange;
  onValidationChangeRef.current = onValidationChange;

  useImperativeHandle(ref, () => ({
    getValue: () => viewRef.current?.state.doc.toString() ?? '',
    setValue: (val: string) => {
      const view = viewRef.current;
      if (!view) return;
      isExternalUpdate.current = true;
      view.dispatch({
        changes: { from: 0, to: view.state.doc.length, insert: val },
      });
      isExternalUpdate.current = false;
    },
    getView: () => viewRef.current,
  }));

  useEffect(() => {
    if (!containerRef.current) return;

    const jsonLinter = linter(jsonParseLinter(), {
      delay: 300,
      markerFilter: diagnostics => {
        const hasErrors = diagnostics.some(d => d.severity === 'error');
        const firstError = diagnostics.find(d => d.severity === 'error');
        onValidationChangeRef.current?.(
          hasErrors,
          firstError ? firstError.message : null,
        );
        return diagnostics;
      },
    });

    const updateListener = EditorView.updateListener.of(update => {
      if (update.docChanged && !isExternalUpdate.current) {
        const doc = update.state.doc.toString();
        onChangeRef.current(doc);
      }
    });

    const state = EditorState.create({
      doc: value,
      extensions: [
        lineNumbers(),
        highlightActiveLineGutter(),
        highlightActiveLine(),
        drawSelection(),
        rectangularSelection(),
        bracketMatching(),
        foldGutter(),
        highlightSelectionMatches(),
        history(),
        json(),
        syntaxHighlighting(defaultHighlightStyle, { fallback: true }),
        lintGutter(),
        jsonLinter,
        sduiTheme,
        updateListener,
        keymap.of([
          ...defaultKeymap,
          ...historyKeymap,
          ...foldKeymap,
          ...searchKeymap,
          indentWithTab,
        ]),
        EditorView.lineWrapping,
        EditorState.tabSize.of(2),
      ],
    });

    const view = new EditorView({
      state,
      parent: containerRef.current,
    });

    viewRef.current = view;

    return () => {
      view.destroy();
      viewRef.current = null;
    };
  }, []);

  useEffect(() => {
    const view = viewRef.current;
    if (!view) return;
    const currentDoc = view.state.doc.toString();
    if (currentDoc !== value) {
      isExternalUpdate.current = true;
      view.dispatch({
        changes: { from: 0, to: view.state.doc.length, insert: value },
      });
      isExternalUpdate.current = false;
    }
  }, [value]);

  return (
    <div
      ref={containerRef}
      style={{ height: '100%', overflow: 'hidden' }}
    />
  );
});

