      expect(typoWarning!.message).toContain('did you mean "heading"');
    });

    it('suggests "button" for "buton"', () => {
      const result = lint({
        id: 'test',
        body: [{ type: 'buton', props: { text: 'Click' } }],
      });
      const typoWarning = result.find(d => d.message.includes('buton'));
