import { chromium } from 'playwright';

const STORYBOOK_URL = 'http://localhost:6006';

async function main() {
  const browser = await chromium.launch({ headless: true });
  const page = await browser.newPage({ viewport: { width: 1600, height: 900 } });

  // Navigate to SDUI Demo Voucher Form story
  await page.goto(`${STORYBOOK_URL}/?path=/story/sdui-demo-voucher-screens--form`, {
    waitUntil: 'networkidle',
  });
  await page.waitForTimeout(3000);

  // Screenshot 1: Valid JSON — no schema errors
  await page.screenshot({
    path: '.storybook/screenshots/schema-validation-valid.png',
    fullPage: false,
  });
  console.log('Screenshot 1: Valid JSON state captured');

  // Now modify JSON in the editor to introduce errors
  // Find the CodeMirror editor in the right panel
  const editorPanel = page.locator('.cm-editor');
  if (await editorPanel.count() > 0) {
    // Click into the editor
    await editorPanel.first().click();

    // Select all text and replace with invalid JSON
    await page.keyboard.press('Meta+a');
    await page.waitForTimeout(200);

    const invalidJson = JSON.stringify({
      id: 'test-errors',
      body: [
        { type: 'headng', props: { text: 'Typo in type' } },
        { type: 'button', props: {} },
        { type: 'heading', props: { colour: 'red' } },
      ],
    }, null, 2);

    await page.keyboard.type(invalidJson, { delay: 1 });
    await page.waitForTimeout(2000);

    // Screenshot 2: Schema errors visible (typos, missing props)
    await page.screenshot({
      path: '.storybook/screenshots/schema-validation-errors.png',
      fullPage: false,
    });
    console.log('Screenshot 2: Schema validation errors captured');

    // Click on a lint marker to show the tooltip
    const lintMarker = page.locator('.cm-lint-marker');
    if (await lintMarker.count() > 0) {
      await lintMarker.first().click();
      await page.waitForTimeout(1000);

      await page.screenshot({
        path: '.storybook/screenshots/schema-validation-tooltip.png',
        fullPage: false,
      });
      console.log('Screenshot 3: Error tooltip captured');
    } else {
      console.log('No lint markers found — trying diagnostics panel');
      // Look for diagnostic messages in the panel
      const diagnostics = page.locator('.cm-diagnostic');
      if (await diagnostics.count() > 0) {
        await page.screenshot({
          path: '.storybook/screenshots/schema-validation-tooltip.png',
          fullPage: false,
        });
        console.log('Screenshot 3: Diagnostics panel captured');
      }
    }
  } else {
    console.log('CodeMirror editor not found in the panel');
  }

  await browser.close();
  console.log('Done!');
}

main().catch(e => { console.error(e); process.exit(1); });

